import { css } from '@emotion/css'
import invariant from '@guanghechen/invariant'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import {
  SudokuCoreActionType,
  SudokuCoreContextType,
  checkCompleted,
} from '@kyokuya/react-game-sudoku-core'
import { Modal } from '@mui/material'
import React from 'react'
import { SudokuInput } from './component/SudokuInput'
import { GameOverlay } from './container/GameOverlay'
import { GameSettings } from './container/GameSettings'
import { GameToolbar } from './container/GameToolbar'
import { SudokuBoard } from './container/SudokuBoard'

export const SudokuGameMain: React.FC = () => {
  const { state, dispatch } = React.useContext(SudokuCoreContextType)
  const {
    SUDOKU_SIZE_SQRT,
    puzzle,
    solution,
    attempt,
    difficulty,
    radix,
    gameStatus,
    usedTimeRef,
    hintCell,
    attemptTick,
    cheatVisible,
  } = state

  const containerRef = React.useRef<HTMLDivElement>(null)
  const sudokuValueRef = React.useRef<string>('')
  const [inputDialogVisible, setInputDialogVisible] = React.useState<boolean>(false)

  const actions = React.useMemo(
    () => ({
      closeCheat: () => {
        dispatch({ type: SudokuCoreActionType.TOGGLE_CHEAT_VISIBILITY, payload: false })
      },
      handleInput: (text: string) => {
        setInputDialogVisible(false)
        sudokuValueRef.current = text

        const value = /^\s*$/.test(text) ? 0 : Number.parseInt(text, radix)
        if (Number.isInteger(value)) {
          dispatch({ type: SudokuCoreActionType.INPUT, payload: value - 1 })
        }
      },
      handleCellClick: (r: number, c: number) => {
        if (r === -1 || c === -1 || puzzle[r][c] !== -1) return
        setInputDialogVisible(true)
      },
    }),
    [radix, puzzle, dispatch],
  )

  React.useEffect(() => {
    const isCompleted: boolean = checkCompleted(
      SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT,
      attempt,
      solution,
    )
    if (!isCompleted) return

    let score = 0
    const totalTime: number = SUDOKU_SIZE_SQRT ** 4 * 1000

    if (usedTimeRef.current < totalTime) {
      const totalScore: number = (SUDOKU_SIZE_SQRT ** 4 * difficulty) / 100
      score = ((totalTime - usedTimeRef.current) * totalScore) / 1000
    }

    dispatch({ type: SudokuCoreActionType.FINISHED, payload: score })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [SUDOKU_SIZE_SQRT, attemptTick, gameStatus])

  invariant(
    SUDOKU_SIZE_SQRT >= 2 && SUDOKU_SIZE_SQRT <= 7,
    '`childMatrixSize` must be an integer in the range [2, 7].',
  )

  const classes = useStyles()
  const SUDOKU_SIZE: number = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  return (
    <div
      ref={containerRef}
      className={classes.sudoku}
      data-sudoku-status={gameStatus}
      data-sudoku-size={`${SUDOKU_SIZE}x${SUDOKU_SIZE}`}
    >
      <div className={classes.sudokuWrapper}>
        <GameSettings />
        <GameToolbar containerRef={containerRef} />
        <div className={classes.sudokuMain}>
          <div className={classes.sudokuMainWrapper}>
            <SudokuBoard
              className={classes.sudokuBoardPuzzle}
              attempt={attempt}
              hintCell={hintCell}
              overlay={<GameOverlay />}
              onCellClick={actions.handleCellClick}
            />
            <Modal
              open={cheatVisible}
              container={containerRef.current}
              keepMounted={true}
              disableAutoFocus={true}
              BackdropProps={{ timeout: 500 }}
              closeAfterTransition={true}
              onClose={actions.closeCheat}
            >
              <div className={classes.sudokuSolution} onClick={actions.closeCheat}>
                <span className={classes.sudokuSolutionClose}>&times;</span>
                <div onClick={e => e.stopPropagation()}>
                  <SudokuBoard attempt={solution} hintCell={null} />
                </div>
              </div>
            </Modal>
          </div>
        </div>
      </div>
      <SudokuInput
        radix={state.radix}
        container={containerRef.current}
        initialValue={sudokuValueRef.current}
        visible={inputDialogVisible}
        label={`A ${radix === 10 ? 'decimal' : 'hexadecimal'} number`}
        onCancel={() => setInputDialogVisible(false)}
        onConfirm={actions.handleInput}
      />
    </div>
  )
}

const useStyles = () => {
  return React.useMemo(() => {
    return {
      sudoku: css`
        display: block;
        transform: scale(1);
        caret-color: transparent;
        --kyokuya-sudoku__font-size: 18px;
        &[data-sudoku-size="4x4"] {
          --kyokuya-sudoku__font-size: 24px;
        }
      `,
      sudokuSolution: css`
        position: relative;
        display: flex;
        justify-content: center;
        align-items: center;
        height: 100%;
        width: 100%;
        background: #eddede;
      `,
      sudokuSolutionClose: css`
        position: absolute;
        top: 0;
        right: 0;
        bottom: unset;
        left: unset;
        display: inline-block;
        height: 48px;
        width: 48px;
        line-height: 48px;
        font-size: 32px;
        text-align: center;
        vertical-align: center;
        color: #333;
        cursor: pointer;
      `,
      sudokuWrapper: css`
        display: block;
        max-width: 90vw;
        margin: auto;
      `,
      sudokuMain: css`
        display: flex;
        justify-content: center;
        padding: 1rem;
        margin: 0;
      `,
      sudokuMainWrapper: css`
        display: block;
        overflow: auto;
        font-size: 16px;
      `,
      sudokuBoardPuzzle: css`
        [data-sudoku-status="${GameRunningStatus.PENDING}"] && {
          --kyokuya-sudoku__board-border-thickness-color: transparent;
          --kyokuya-sudoku__board-border-thickness-plus-color: transparent;
        }
        [data-sudoku-status="${GameRunningStatus.PAUSED}"] && {
          --kyokuya-sudoku__board-border-thickness-color: transparent;
          --kyokuya-sudoku__board-border-thickness-plus-color: transparent;
        }
        [data-sudoku-status="${GameRunningStatus.FINISHED}"] && {
          --kyokuya-sudoku__board-border-thickness-color: transparent;
          --kyokuya-sudoku__board-border-thickness-plus-color: transparent;
        }
      `,
    }
  }, [])
}
