/* eslint-disable no-param-reassign */
import type { ISudokuBoard } from '@algorithm.ts/sudoku'

export function generateDuplicatedMap(
  SUDOKU_SIZE_SQRT: number,
  attempt: Readonly<ISudokuBoard>,
): Uint8Array {
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  const size = SUDOKU_SIZE * SUDOKU_SIZE
  const duplicatedMap = new Uint8Array(size).fill(0)

  // Scan row.
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    for (let c = 0, bitset = 0; c < SUDOKU_SIZE; ++c) {
      const v: number = attempt[r][c]
      if (v === -1) continue

      const s: number = 1 << v
      if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
      bitset |= s
    }

    for (let c = SUDOKU_SIZE - 1, bitset = 0; c >= 0; --c) {
      const v: number = attempt[r][c]
      if (v === -1) continue

      const s: number = 1 << v
      if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
      bitset |= s
    }
  }

  // Scan column.
  for (let c = 0; c < SUDOKU_SIZE; ++c) {
    for (let r = 0, bitset = 0; r < SUDOKU_SIZE; ++r) {
      const v: number = attempt[r][c]
      if (v === -1) continue

      const s: number = 1 << v
      if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
      bitset |= s
    }

    for (let r = SUDOKU_SIZE - 1, bitset = 0; r >= 0; --r) {
      const v: number = attempt[r][c]
      if (v === -1) continue

      const s: number = 1 << v
      if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
      bitset |= s
    }
  }

  // Scan sub matrix.
  for (let r0 = 0; r0 < SUDOKU_SIZE; r0 += SUDOKU_SIZE_SQRT) {
    for (let c0 = 0; c0 < SUDOKU_SIZE; c0 += SUDOKU_SIZE_SQRT) {
      for (let x = 0, bitset = 0; x < SUDOKU_SIZE_SQRT; ++x) {
        for (let y = 0; y < SUDOKU_SIZE_SQRT; ++y) {
          const r: number = r0 + x
          const c: number = c0 + y
          const v: number = attempt[r][c]
          if (v === -1) continue

          const s: number = 1 << v
          if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
          bitset |= s
        }
      }

      for (let x = SUDOKU_SIZE_SQRT - 1, bitset = 0; x >= 0; --x) {
        for (let y = SUDOKU_SIZE_SQRT - 1; y >= 0; --y) {
          const r: number = r0 + x
          const c: number = c0 + y
          const v: number = attempt[r][c]
          if (v === -1) continue

          const s: number = 1 << v
          if (bitset & s) duplicatedMap[r * SUDOKU_SIZE + c] = 1
          bitset |= s
        }
      }
    }
  }
  return duplicatedMap
}
