import { Loading } from '@kyokuya/core-component'
import { assign, pick } from '@kyokuya/core-util'
import type { ISudokuCoreState as IState } from '@kyokuya/react-game-sudoku-core'
import { SudokuCoreContextProvider, initSudokuCoreState } from '@kyokuya/react-game-sudoku-core'
import { useAsyncState } from '@kyokuya/react-storage'
import PropTypes from 'prop-types'
import React from 'react'
import { SudokuPersistent } from './container/SudokuPersistent'
import { SudokuGameMain } from './SudokuGameMain'

export interface ISudokuGameProps {
  storageKey?: string
  initialState?: Partial<IState> | Promise<Partial<IState>>
}

export const SudokuGame: React.FC<ISudokuGameProps> = props => {
  const { loading, data, save } = useAsyncState<IState>(props.storageKey, {
    deserialize: async initialData =>
      initSudokuCoreState(assign<Partial<IState>>({ ...initialData }, await props.initialState)),
    serialize: latestData =>
      pick(latestData, [
        'SUDOKU_SIZE_SQRT',
        'difficulty',
        'radix',
        'score',
        'puzzle',
        'solution',
        'instructions',
        'activatedCell',
        'usedTimeRef',
      ]),
  })

  if (loading) return <Loading />

  return (
    <SudokuCoreContextProvider initialState={data}>
      <SudokuPersistent onStateChange={save} />
      <SudokuGameMain />
    </SudokuCoreContextProvider>
  )
}

SudokuGame.propTypes = {
  storageKey: PropTypes.string.isRequired,
  initialState: PropTypes.any,
}
