import type { ISudokuCoreState } from '@kyokuya/react-game-sudoku-core'
import { SudokuCoreActionType, SudokuCoreContextType } from '@kyokuya/react-game-sudoku-core'
import React from 'react'

export interface ISudokuPersistentProps {
  onStateChange(state: ISudokuCoreState): Promise<void> | void
}

export const SudokuPersistent: React.FC<ISudokuPersistentProps> = ({ onStateChange }) => {
  const { state, dispatch } = React.useContext(SudokuCoreContextType)

  React.useEffect(() => {
    const beforeunload = (): void => dispatch({ type: SudokuCoreActionType.PAUSE })
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [dispatch])

  React.useEffect(() => {
    if (state !== null) {
      void onStateChange(state)
    }
  }, [state, onStateChange])
  return <React.Fragment />
}
